 87→export function snapToGrid(value, grid = SHEET_TOKENS.viewportGrid) {
 88→  return Math.round(value / grid) * grid;
 89→}
 90→
 91→export function snapRectToGrid(rect, grid = SHEET_TOKENS.viewportGrid) {
 92→  return {
 93→    x: snapToGrid(rect.x, grid),
 94→    y: snapToGrid(rect.y, grid),
 95→    width: Math.max(grid, snapToGrid(rect.width, grid)),
 96→    height: Math.max(grid, snapToGrid(rect.height, grid)),
 97→  };
 98→}
