100→export function formatSheetDate(value) {
101→  if (!value) return '';
102→  const date = new Date(value);
103→  if (Number.isNaN(date.getTime())) return String(value);
104→  const year = date.getFullYear();
105→  const month = String(date.getMonth() + 1).padStart(2, '0');
106→  const day = String(date.getDate()).padStart(2, '0');
107→  return `${year}-${month}-${day}`;
108→}
109→
110→export function formatDrawingMeasurement(mm) {
111→  return `${Math.round(Math.abs(Number(mm) || 0))} mm`;
112→}
113→
114→export function formatDrawingArea(area) {
115→  const value = Number(area) || 0;
116→  if (value <= 0) return '';
117→  return `${(value / 1_000_000).toFixed(2)} m²`;
118→}
119→
120→export function resolveViewportScaleLabel(viewport, source, sheet) {
121→  if (source?.kind === '3d_preview') return 'NTS';
122→  if (sheet?.scaleMode === 'as_noted') return 'As noted';
123→  return `1:${Math.max(1, Math.round(Number(viewport?.scale) || 100))}`;
124→}
125→
126→export function resolveViewportReferenceNote(viewport, source) {
127→  const custom = viewport?.referenceNote?.trim();
128→  if (custom) return custom;
129→  if (source?.kind === '3d_preview') return 'AXONOMETRIC VIEW';
130→  if (source?.kind === 'section') return 'BUILDING SECTION';
131→  if (source?.kind === 'elevation') return 'EXTERIOR ELEVATION';
132→  return 'CONSTRUCTION VIEW';
133→}
134→
135→export function resolveSheetScaleLabel(sheet, viewports = []) {
136→  if (sheet?.scaleMode === 'as_noted') return 'As noted';
137→  if (sheet?.scaleMode === 'per_viewport') return 'As noted';
138→
139→  const explicit = sheet?.scaleLabel?.trim();
140→  if (explicit) return explicit;
141→
142→  const scales = [...new Set(viewports
143→    .filter((viewport) => viewport.source?.kind !== '3d_preview')
144→    .map((viewport) => Math.max(1, Math.round(Number(viewport.scale) || 100))) )];
145→
146→  if (scales.length === 1) return `1:${scales[0]}`;
147→  return 'As noted';
148→}
