167→                    stroke="#0f8f74"
168→                    strokeWidth={0.4}
169→                  />
170→                  <circle
171→                    cx={rh.cx}
172→                    cy={rh.cy}
173→                    r={rh.radius}
174→                    fill="#ffffff"
175→                    stroke="#0f8f74"
176→                    strokeWidth={0.5}
177→                    style={{ cursor: 'grab' }}
178→                  />
179→                </>
180→              );
181→            })()}
182→          </g>
183→        );
