26→export function hitTestViewportHandle(point, viewports, handleSize) {
27→  for (let index = viewports.length - 1; index >= 0; index -= 1) {
28→    const viewport = viewports[index];
29→    const handles = getViewportHandleRects(viewport, handleSize);
30→    for (const [key, rect] of Object.entries(handles)) {
31→      if (pointInRect(point, rect)) {
32→        return { viewportId: viewport.id, handle: key };
33→      }
34→    }
35→  }
36→  return null;
37→}
